pragma solidity ^0.8.7;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/cryptography/MerkleProof.sol";

contract MyNFT is ERC721, Ownable {
    using MerkleProof for bytes32[];

    struct MintInfo {
        uint256 presaleStartTime;
        uint256 publicSaleStartTime;
        uint256 maxSupply;
        uint256 price;
        string baseURI;
        bool revealed;
        bool paused;
    }

    MintInfo public mintInfo;

    mapping(address => uint256) public presaleAllowance;
    mapping(address => uint256) public mintedCount;

    event TokenMinted(address indexed to, uint256 tokenId);
    event SaleStarted(string state);
    event SalePaused();

    constructor(
        uint256 _maxSupply,
        uint256 _price,
        uint256 _presaleStartTime,
        uint256 _publicSaleStartTime,
        string memory _baseURI
    ) ERC721("MyNFT", "MNFT") {
        mintInfo = MintInfo({
            presaleStartTime: _presaleStartTime,
            publicSaleStartTime: _publicSaleStartTime,
            maxSupply: _maxSupply,
            price: _price,
            baseURI: _baseURI,
            revealed: false,
            paused: false
        });
    }

    modifier inPresalePeriod() {
        require(block.timestamp >= mintInfo.presaleStartTime, "Presale has not started");
        _;
    }

    modifier inPublicSalePeriod() {
        require(block.timestamp >= mintInfo.publicSaleStartTime, "Public sale has not started");
        _;
    }

    modifier notPaused() {
        require(!mintInfo.paused, "Contract is paused");
        _;
    }

    modifier onlyWhenUnpaused() {
        require(!mintInfo.paused, "Contract is paused");
        _;
